'use client';

import { useCallback, useEffect, useState } from "react";
import { useRouter } from "next/navigation";
import type { Route } from "next";

import { AdminDashboard } from "@/components/AdminDashboard";
import { useAuth } from "@/context/AuthContext";
import { fetchAdminReports, updateReportStatus } from "@/lib/api";
import { colors } from "@/theme/colors";
import type { ReportRecord, ReportStatus, Role } from "@/types/domain";

const allowedRoles: Role[] = ["ADMIN", "MODERATOR"];

export default function AdminPage() {
  const router = useRouter();
  const { user, isReady } = useAuth();
  const token = user?.token;

  const [reports, setReports] = useState<ReportRecord[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    if (!isReady) return;
    if (!user || !token || !allowedRoles.includes(user.role)) {
      router.replace("/" as Route);
    }
  }, [isReady, user, token, router]);

  const loadReports = useCallback(async () => {
    if (!token) {
      setIsLoading(false);
      return;
    }
    setIsLoading(true);
    setError(null);
    try {
      const data = await fetchAdminReports(token);
      setReports(data);
    } catch (err) {
      const message = err instanceof Error ? err.message : "Nu am putut încărca rapoartele";
      setError(message);
    } finally {
      setIsLoading(false);
    }
  }, [token]);

  useEffect(() => {
    if (!token) return;
    void loadReports();
  }, [token, loadReports]);

  const handleStatusChange = useCallback(
    async (reportId: number, nextStatus: ReportStatus) => {
      if (!token) return;
      await updateReportStatus(reportId, nextStatus, token);
      await loadReports();
    },
    [token, loadReports]
  );

  return (
    <main className="relative min-h-screen overflow-hidden" style={{ backgroundColor: colors.backgroundMuted }}>
      <div className="relative z-10 mx-auto flex w-full max-w-7xl flex-col gap-8 py-10">
        <div className="flex flex-wrap items-center justify-between gap-4 px-6">
          <div>
            <p className="text-sm font-semibold uppercase tracking-[0.3em]" style={{ color: colors.textSecondary }}>
              CitySafe Control Room
            </p>
            <h1 className="mt-2 text-3xl font-bold md:text-4xl" style={{ color: colors.textPrimary }}>
              Monitorizează rapoartele și gestionează prezența lor pe hartă
            </h1>
          </div>
          <button
            type="button"
            onClick={() => void loadReports()}
            className="rounded-full border px-5 py-2 text-sm font-semibold transition hover:bg-[#E2E8F0]"
            style={{ borderColor: colors.border, color: colors.textSecondary, backgroundColor: colors.background }}
            disabled={isLoading}
          >
            Reîmprospătează
          </button>
        </div>
        <section
          className="rounded-[32px] px-2 py-4 shadow-card"
          style={{ backgroundColor: colors.background, border: `1px solid ${colors.placeholder}` }}
        >
          <AdminDashboard
            reports={reports}
            isLoading={isLoading}
            error={error}
            onStatusChange={handleStatusChange}
          />
        </section>
      </div>
    </main>
  );
}
